mapper.select:
select c.*, case when c.type = 'article' then i.title when c.type = 'post' then p.title when c.type = 'news' then n.title else '' end as introductionTitle, case when c.type = 'article' then i.content when c.type = 'post' then p.content when c.type = 'news' then n.content else '' end as introductionDescription, case when c.type = 'article' then i.img when c.type = 'post' then '' when c.type = 'news' then n.img else '' end as introductionImg from `collect` c left join `introduction` i on c.type = 'article' and c.introduction_id = i.id left join `post` p on c.type = 'post' and c.introduction_id = p.id left join `news` n on c.type = 'news' and c.introduction_id = n.id where c.user_id = #{userId}
and c.type = #{type}
order by c.time desc
